class Solution {
public:
    int removeDuplicates(vector<int>& nums) {
        if (nums.empty())
            return 0;

        int ar_i = 1;

        for (int i = 0; i < nums.size(); i++){
            if(nums[i] != nums[ar_i-1]){
                nums[ar_i] = nums[i];
                ar_i++;
            }

        }

        return ar_i;
    }
};
